{
  "sentences": [
    {
      "text": "我為了學中文來台灣。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1.",
      "translation_en": "I came to Taiwan to learn Chinese.",
      "translation_ko": "저는 중국어를 배우기 위해 대만에 왔어요."
    },
    {
      "text": "他為了工作搬到台北。",
      "pinyin": "Tā wèile gōngzuò bān dào Táiběi.",
      "pinyin_numeric": "ta1 wei4 le5 gong1 zuo4 ban1 dao4 Tai2 bei3.",
      "translation_en": "He moved to Taipei for work.",
      "translation_ko": "그는 일 때문에 타이베이로 이사했어요."
    },
    {
      "text": "她為了留學來台灣。",
      "pinyin": "Tā wèile liúxué lái Táiwān.",
      "pinyin_numeric": "ta1 wei4 le5 liu2 xue2 lai2 Tai2 wan1.",
      "translation_en": "She came to Taiwan to study abroad.",
      "translation_ko": "그녀는 유학을 위해 대만에 왔어요."
    },
    {
      "text": "我為了學中文來台灣，因為我喜歡台灣的文化。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, yīnwèi wǒ xǐhuān Táiwān de wénhuà.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, yin1 wei4 wo3 xi3 huan1 Tai2 wan1 de5 wen2 hua4.",
      "translation_en": "I came to Taiwan to learn Chinese because I like Taiwanese culture.",
      "translation_ko": "저는 대만 문화를 좋아해서 중국어를 배우기 위해 대만에 왔어요."
    },
    {
      "text": "他為了當醫生來台灣上課。",
      "pinyin": "Tā wèile dāng yīshēng lái Táiwān shàngkè.",
      "pinyin_numeric": "ta1 wei4 le5 dang1 yi1 sheng1 lai2 Tai2 wan1 shang4 ke4.",
      "translation_en": "He came to Taiwan to take classes to become a doctor.",
      "translation_ko": "그는 의사가 되기 위해 대만에서 수업을 들어요."
    },
    {
      "text": "我為了學中文來台灣，已經學了半年。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, yǐjīng xué le bàn nián.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, yi3 jing1 xue2 le5 ban4 nian2.",
      "translation_en": "I came to Taiwan to learn Chinese, and I've been studying for half a year.",
      "translation_ko": "저는 중국어를 배우기 위해 대만에 왔는데, 벌써 반 년 동안 공부했어요."
    },
    {
      "text": "她為了工作從鄉下搬到城市。",
      "pinyin": "Tā wèile gōngzuò cóng xiāngxià bān dào chéngshì.",
      "pinyin_numeric": "ta1 wei4 le5 gong1 zuo4 cong2 xiang1 xia4 ban1 dao4 cheng2 shi4.",
      "translation_en": "She moved from the countryside to the city for work.",
      "translation_ko": "그녀는 일 때문에 시골에서 도시로 이사했어요."
    },
    {
      "text": "我為了學中文來台灣，希望將來可以說得很流利。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, xīwàng jiānglái kěyǐ shuō de hěn liúlì.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, xi1 wang4 jiang1 lai2 ke3 yi3 shuo1 de5 hen3 liu2 li4.",
      "translation_en": "I came to Taiwan to learn Chinese, hoping to speak fluently in the future.",
      "translation_ko": "저는 중국어를 배우기 위해 대만에 왔으며, 앞으로 유창하게 말할 수 있기를 바래요."
    },
    {
      "text": "他為了考試通過來台灣上課。",
      "pinyin": "Tā wèile kǎoshì tōngguò lái Táiwān shàngkè.",
      "pinyin_numeric": "ta1 wei4 le5 kao3 shi4 tong1 guo4 lai2 Tai2 wan1 shang4 ke4.",
      "translation_en": "He came to Taiwan to take classes in order to pass the exam.",
      "translation_ko": "그는 시험에 합격하기 위해 대만에서 수업을 들어요."
    },
    {
      "text": "我為了學中文來台灣，因為我的興趣是台灣文化。",
      "pinyin": "Wǒ wèile xué Zhōngwén lái Táiwān, yīnwèi wǒ de xìngqù shì Táiwān wénhuà.",
      "pinyin_numeric": "wo3 wei4 le5 xue2 Zhong1 wen2 lai2 Tai2 wan1, yin1 wei4 wo3 de5 xing4 qu4 shi4 Tai2 wan1 wen2 hua4.",
      "translation_en": "I came to Taiwan to learn Chinese because my interest is Taiwanese culture.",
      "translation_ko": "저는 대만 문화에 관심이 있어서 중국어를 배우기 위해 대만에 왔어요."
    }
  ]
}
